@@ -457,6 +457,21 @@ using SCEV2ValueTy = DenseMap<const SCEV *, Value *>;
 } // namespace

 namespace llvm {
+static void fixDominanceIssues(Function &F) {
+  for (auto &BB : F) {
+    for (auto &I : BB) {
+      if (auto *Phi = dyn_cast<PHINode>(&I)) {
+        for (unsigned i = 0, e = Phi->getNumIncomingValues(); i != e; ++i) {
+          if (auto *Inst = dyn_cast<Instruction>(Phi->getIncomingValue(i))) {
+            if (Inst->getParent() == &BB && !Inst->comesBefore(Phi)) {
+              Inst->moveBefore(Phi);
+            }
+          }
+        }
+      }
+    }
+  }
+}

 AnalysisKey ShouldRunExtraVectorPasses::Key;

@@ -10339,6 +10354,8 @@ bool LoopVectorizePass::processLoop(Loop *L) {
     // Mark the loop as already vectorized to avoid vectorizing again.
     Hints.setAlreadyVectorized();
   }
+  // Fix dominance issues for vector recurrence phis.
+  fixDominanceIssues(*L->getHeader()->getParent());

   assert(!verifyFunction(*L->getHeader()->getParent(), &dbgs()));
   return true;
